<?php
namespace App\Http\Controllers\Auth;
use App\Http\Controllers\Controller;use App\Models\User;use App\Services\Security\AuditLogger;use Illuminate\Http\RedirectResponse;use Illuminate\Http\Request;use Illuminate\Support\Facades\Auth;use Illuminate\Support\Facades\Hash;use Inertia\Inertia;use Inertia\Response;
class TwoFactorController extends Controller{public function create(Request $request):Response|RedirectResponse{if(!$request->session()->has('two_factor_user_id'))return redirect()->route('login');return Inertia::render('Auth/TwoFactorChallenge');}public function store(Request $request):RedirectResponse{$v=$request->validate(['code'=>['required','digits:6']]);$user=User::find($request->session()->get('two_factor_user_id'));if(!$user||!$user->two_factor_code_expires_at?->isFuture()||!Hash::check($v['code'],(string)$user->two_factor_code_hash)){if($user)AuditLogger::record($request,'two_factor_failed','authentication','critical','Invalid administrator verification code.',$user);return back()->withErrors(['code'=>'The verification code is invalid or expired.']);}Auth::login($user);$request->session()->forget('two_factor_user_id');$request->session()->regenerate();$user->forceFill(['last_login_at'=>now(),'two_factor_code_hash'=>null,'two_factor_code_expires_at'=>null])->save();AuditLogger::record($request,'login_succeeded','authentication','normal','Administrator completed two-factor sign-in.',$user);return redirect()->intended(route('dashboard',absolute:false));}}
